package com.nattechnologies.trastcms.plugins.saas; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="saas_activation") class SaasActivation{@Id@Column(length=36)String id;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="license_id")SaasLicense license;@Column(name="fingerprint_hash",nullable=false,length=64)String fingerprintHash;@Column(name="device_name",length=180)String deviceName;@Column(length=80)String platform;@Column(name="application_version",length=80)String applicationVersion;@Enumerated(EnumType.STRING)@Column(nullable=false,length=30)ActivationStatus status=ActivationStatus.ACTIVE;@Column(name="activated_at",nullable=false)Instant activatedAt;@Column(name="last_heartbeat_at")Instant lastHeartbeatAt;@Column(name="deactivated_at")Instant deactivatedAt;@PrePersist void create(){if(id==null)id=UUID.randomUUID().toString();}}
